                                   <!-- <th class=\\\"text-center\\\">\\r\\n                                                            P. Defecto\\r\\n                                                        </th> -->\\r\\n                                            <th class=\\\"text-white\\\">\\r\\n                                                MAX\\r\\n                                                <el-tooltip class=\\\"item\\\" effect=\\\"dark\\\" content=\\\"Check para indicar que es la Maxima cantdad en su presentación\\\" placement=\\\"top\\\">\\r\\n                                                    <i class=\\\"fa fa-info-circle\\\"></i>\\r\\n                                                </el-tooltip>\\r\\n                                            </th>\\r\\n                                            <th></th>\\r\\n                                        </tr>\\r\\n                                    </thead>\\r\\n                                    <tbody>\\r\\n                                        <tr v-for=\\\"(row,\\r\\n                                                        index) in form.item_unit_types\\\" :key=\\\"index\\\">\\r\\n                                            <template v-if=\\\"row.id\\\">\\r\\n                                                <td class=\\\"text-center\\\">\\r\\n                                                    {{ row.unit_type_id }}\\r\\n                                                </td>\\r\\n                                                <td class=\\\"text-center\\\">\\r\\n                                                    {{ row.description }}\\r\\n                                                </td>\\r\\n                                                <td class=\\\"text-center\\\">\\r\\n                                                    {{ row.quantity_unit }}\\r\\n                                                </td>\\r\\n                                                <td class=\\\"text-center\\\">\\r\\n                                                    <el-input v-model=\\\"row.price2\\\" @input=\\\"\\r\\n                                                                        undToTotal(\\r\\n                                                                            index,\\r\\n                                                                            row.price2,\\r\\n                                                                            row.quantity_unit\\r\\n                                                                        )\\r\\n                                                                    \\\">\\r\\n                                                        <i slot=\\\"prefix\\\" class=\\\"el-icon-edit-outline\\\"></i></el-input>\\r\\n                                                </td>\\r\\n\\r\\n                                                <!-- <td class=\\\"text-center\\\">\\r\\n    <el-input\\r\\n        v-model=\\\"row.total\\\"\\r\\n        placeholder=\\\"0.00\\\"\\r\\n        @input=\\\"validateInput(index, row)\\\"\\r\\n    >\\r\\n        <template slot=\\\"prefix\\\">\\r\\n            <i class=\\\"el-icon-edit-outline\\\"></i>\\r\\n        </template>\\r\\n        <input\\r\\n            slot=\\\"append\\\"\\r\\n            type=\\\"text\\\"\\r\\n            v-model=\\\"row.total\\\"\\r\\n            class=\\\"el-input__inner\\\"\\r\\n            style=\\\"border:none; width:100%; text-align:center;\\\"\\r\\n        />\\r\\n    </el-input>\\r\\n    <div v-if=\\\"row.error\\\" class=\\\"error-message\\\">Solo se aceptan números</div>\\r\\n</td> -->\\r\\n\\r\\n                                                <td class=\\\"text-center\\\">\\r\\n                                                    <el-input v-model=\\\"row.total\\\" @input=\\\" totalToUnd(index,row.total,row.quantity_unit)\\\" type=\\\"number\\\" step=\\\"0.01\\\" pattern=\\\"^\\\\d*(\\\\.\\\\d{0,2})?$\\\">\\r\\n                                                        <i slot=\\\"prefix\\\" class=\\\"el-icon-edit-outline\\\"></i>\\r\\n                                                    </el-input>\\r\\n                                                </td>\\r\\n                                                <td>\\r\\n                                                    <el-select clearable v-model=\\\"\\r\\n                                                                        row.warehouse_id\\r\\n                                                                    \\\">\\r\\n                                                        <el-option v-for=\\\"w in warehouses\\\" :key=\\\"w.id\\\" :value=\\\"w.id\\\" :label=\\\"\\r\\n                                                                            w.description\\r\\n                                                                        \\\"></el-option>\\r\\n                                                    </el-select>\\r\\n                                                </td>\\r\\n                                                <td class=\\\"text-center\\\">\\r\\n                                                    <el-checkbox v-model=\\\"\\r\\n                                                                        row.selected\\r\\n                                                                    \\\" @change=\\\"\\r\\n                                                                        selectedMax(\\r\\n                                                                            index\\r\\n                                                                        )\\r\\n                                                                    \\\"></el-checkbox>\\r\\n                                                </td>\\r\\n\\r\\n                                                <td class=\\\"series-table-actions text-end\\\">\\r\\n                                                    <button type=\\\"button\\\" class=\\\"btn waves-effect waves-light btn-sm btn-danger\\\" @click.prevent=\\\"\\r\\n                                                                        clickDelete(\\r\\n                                                                            row.id\\r\\n                                                                        )\\r\\n                                                                    \\\">\\r\\n                                                        <i class=\\\"fa fa-trash\\\"></i>\\r\\n                                                    </button>\\r\\n                                                </td>\\r\\n                                            </template>\\r\\n                                            <template v-else>\\r\\n                                                <td>\\r\\n                                                    <div class=\\\"form-group\\\">\\r\\n                                                        <el-select v-model=\\\"\\r\\n                                                                            row.unit_type_id\\r\\n                                                                        \\\" dusk=\\\"item_unit_type.unit_type_id\\\">\\r\\n                                                            <el-option v-for=\\\"option in unit_types\\\" :key=\\\"\\r\\n                                                                                option.id\\r\\n                                                                            \\\" :value=\\\"\\r\\n                                                                                option.id\\r\\n                                                                            \\\" :label=\\\"\\r\\n                                                                                option.description\\r\\n                                                                            \\\"></el-option>\\r\\n                                                        </el-select>\\r\\n                                                    </div>\\r\\n                                                </td>\\r\\n                                                <td>\\r\\n                                                    <div class=\\\"form-group\\\">\\r\\n                                                        <el-input v-model=\\\"\\r\\n                                                                            row.description\\r\\n                                                                        \\\">\\r\\n                                                            <i slot=\\\"prefix\\\" class=\\\"el-icon-edit-outline\\\"></i></el-input>\\r\\n                                                    </div>\\r\\n                                                </td>\\r\\n                                                <td>\\r\\n                                                    <div class=\\\"form-group\\\">\\r\\n                                                        <el-input @input=\\\"\\r\\n                                                                            undToTotal(\\r\\n                                                                                index,\\r\\n                                                                                row.price2,\\r\\n                                                                                row.quantity_unit\\r\\n                                                                            )\\r\\n                                                                        \\\" v-model=\\\"\\r\\n                                                                            row.quantity_unit\\r\\n                                                                        \\\">\\r\\n                                                            <i slot=\\\"prefix\\\" class=\\\"el-icon-edit-outline\\\"></i></el-input>\\r\\n                                                    </div>\\r\\n                                                </td>\\r\\n                                                <td>\\r\\n                                                    <div class=\\\"form-group\\\">\\r\\n                                                        <el-input v-model=\\\"\\r\\n                                                                            row.price2\\r\\n                                                                        \\\" @input=\\\"\\r\\n                                                                            undToTotal(\\r\\n                                                                                index,\\r\\n                                                                                row.price2,\\r\\n                                                                                row.quantity_unit\\r\\n                                                                            )\\r\\n                                                                        \\\">\\r\\n                                                            <i slot=\\\"prefix\\\" class=\\\"el-icon-edit-outline\\\"></i></el-input>\\r\\n                                                    </div>\\r\\n                                                </td>\\r\\n                                                <td>\\r\\n                                                    <div class=\\\"form-group\\\">\\r\\n                                                        <el-input v-model=\\\"\\r\\n                                                                            row.total\\r\\n                                                                        \\\" @input=\\\"\\r\\n                                                                            totalToUnd(\\r\\n                                                                                index,\\r\\n                                                                                row.total,\\r\\n                                                                                row.quantity_unit\\r\\n                                                                            )\\r\\n                                                                        \\\">\\r\\n                                                            <i slot=\\\"prefix\\\" class=\\\"el-icon-edit-outline\\\"></i></el-input>\\r\\n                                                    </div>\\r\\n                                                </td>\\r\\n                                                <td>\\r\\n                                                    <el-select clearable v-model=\\\"\\r\\n                                                                        row.warehouse_id\\r\\n                                                                    \\\">\\r\\n                                                        <el-option v-for=\\\"w in warehouses\\\" :key=\\\"w.id\\\" :value=\\\"w.id\\\" :label=\\\"\\r\\n                                                                            w.description\\r\\n                                                                        \\\"></el-option>\\r\\n                                                    </el-select>\\r\\n                                                </td>\\r\\n                                                <td>\\r\\n                                                    <el-checkbox v-model=\\\"\\r\\n                                                                        row.selected\\r\\n                                                                    \\\" @change=\\\"\\r\\n                                                                        selectedMax(\\r\\n                                                                            index\\r\\n                                                                        )\\r\\n                                                                    \\\"></el-checkbox>\\r\\n                                                </td>\\r\\n                                                <td class=\\\"series-table-actions text-end\\\">\\r\\n                                                    <button type=\\\"button\\\" class=\\\"btn waves-effect waves-light btn-sm btn-danger\\\" @click.prevent=\\\"\\r\\n                                                                        clickCancel(\\r\\n                                                                            index\\r\\n                                                                        )\\r\\n                                                                    \\\">\\r\\n                                                        <i class=\\\"fa fa-trash\\\"></i>\\r\\n                                                    </button>\\r\\n                                                </td>\\r\\n                                            </template>\\r\\n                                        </tr>\\r\\n                                    </tbody>\\r\\n                                </table>\\r\\n                            </div>\\r\\n                        </div>\\r\\n                    </div>\\r\\n                </el-tab-pane>\\r\\n                <el-tab-pane v-if=\\\"configuration.commercial_treatment_items\\\" label=\\\"Tratamiento Comercial\\\">\\r\\n                    <div class=\\\"row m-2\\\">\\r\\n                        <table>\\r\\n                            <tbody>\\r\\n                                <tr v-for=\\\"(commercial_treatment_item,\\r\\n                                                index) in form.commercial_treatments\\\" :key=\\\"`${index}treatment`\\\">\\r\\n                                    <td>\\r\\n                                        {{\\r\\n                                                        commercial_treatment_item.commercial_treatment_description\\r\\n                                                    }}\\r\\n                                    </td>\\r\\n                                    <td width=\\\"15%\\\">\\r\\n                                        <el-input @input=\\\"\\r\\n                                                            updateCommercialTreatmentItem(\\r\\n                                                                index\\r\\n                                                            )\\r\\n                                                        \\\" type=\\\"number\\\" v-model=\\\"\\r\\n                                                            commercial_treatment_item.amount\\r\\n                                                        \\\"></el-input>\\r\\n                                    </td>\\r\\n                                </tr>\\r\\n                            </tbody>\\r\\n                        </table>\\r\\n                    </div>\\r\\n                </el-tab-pane>\\r\\n                <el-tab-pane label=\\\"Compras\\\">\\r\\n                    <div class=\\\"row\\\">\\r\\n                        <div class=\\\"col-12 col-lg-6 col-xl-6\\\">\\r\\n                            <div class=\\\"form-group\\\" :class=\\\"{\\r\\n                                                'has-danger':\\r\\n                                                    errors.purchase_affectation_igv_type_id\\r\\n                                            }\\\">\\r\\n                                <label class=\\\"control-label\\\">Tipo de afectación (Compra)</label>\\r\\n                                <el-select v-model=\\\"\\r\\n                                                    form.purchase_affectation_igv_type_id\\r\\n                                                \\\">\\r\\n                                    <el-option v-for=\\\"option in affectation_igv_types\\\" :key=\\\"option.id\\\" :value=\\\"option.id\\\" :label=\\\"option.description\\\"></el-option>\\r\\n                                </el-select>\\r\\n                                <small class=\\\"text-danger\\\" v-if=\\\"\\r\\n                                                    errors.purchase_affectation_igv_type_id\\r\\n                                                \\\" v-text=\\\"\\r\\n                                                    errors\\r\\n                                                        .purchase_affectation_igv_type_id[0]\\r\\n                                                \\\"></small>\\r\\n                            </div>\\r\\n                        </div>\\r\\n                        <div class=\\\"col-12 col-lg-6 col-xl-6\\\">\\r\\n                            <div class=\\\"form-group\\\" :class=\\\"{\\r\\n                                                'has-danger': errors.purchase_unit_price\\r\\n                                            }\\\">\\r\\n                                <label class=\\\"control-label\\\">Precio Unitario (Compra)</label>\\r\\n                                <el-input v-model=\\\"form.purchase_unit_price\\\" dusk=\\\"purchase_unit_price\\\" @input=\\\"\\r\\n                                                    calculatePercentageOfProfitByPurchase\\r\\n                                                \\\">\\r\\n                                    <i slot=\\\"prefix\\\" class=\\\"el-icon-edit-outline\\\"></i></el-input>\\r\\n                                <small class=\\\"text-danger\\\" v-if=\\\"errors.purchase_unit_price\\\" v-text=\\\"errors.purchase_unit_price[0]\\\"></small>\\r\\n                            </div>\\r\\n                        </div>\\r\\n                        <!-- <div class=\\\"short-div col-md-4\\\"> -->\\r\\n                        <div class=\\\"col-12 col-lg-6 col-xl-6\\\">\\r\\n                            <div class=\\\"form-group\\\" :class=\\\"{\\r\\n                                                'has-danger':\\r\\n                                                    errors.percentage_of_profit\\r\\n                                            }\\\">\\r\\n                                <label class=\\\"control-label\\\">\\r\\n                                    <el-checkbox v-model=\\\"\\r\\n                                                        enabled_percentage_of_profit\\r\\n                                                    \\\" @change=\\\"\\r\\n                                                        changeEnabledPercentageOfProfit\\r\\n                                                    \\\"></el-checkbox>\\r\\n                                    Porcentaje de ganancia (%)\\r\\n                                </label>\\r\\n                                <el-input v-model=\\\"form.percentage_of_profit\\\" :disabled=\\\"\\r\\n                                                    !enabled_percentage_of_profit\\r\\n                                                \\\" @input=\\\"\\r\\n                                                    calculatePercentageOfProfitByPercentage\\r\\n                                                \\\">\\r\\n                                    <i slot=\\\"prefix\\\" class=\\\"el-icon-edit-outline\\\"></i></el-input>\\r\\n                                <small class=\\\"text-danger\\\" v-if=\\\"errors.percentage_of_profit\\\" v-text=\\\"errors.percentage_of_profit[0]\\\"></small>\\r\\n                            </div>\\r\\n                        </div>\\r\\n                    </div>\\r\\n                </el-tab-pane>\\r\\n            </el-tabs>\\r\\n        </div>\\r\\n        <div class=\\\"form-actions text-end pt-2 pb-2\\\">\\r\\n            <el-button icon=\\\"fas fa-times fa-lg\\\" @click.prevent=\\\"close()\\\"> Cancelar</el-button>\\r\\n            <el-button icon=\\\"fas fa-save fa-lg\\\" type=\\\"primary\\\" native-type=\\\"submit\\\" :loading=\\\"loading_submit\\\"> Guardar</el-button>\\r\\n        </div>\\r\\n    </form>\\r\\n    <!-- <percentage-perception\\r\\n                        :showDialog.sync=\\\"showPercentagePerception\\\"\\r\\n                        :percentage_perception=\\\"percentage_perception\\\">\\r\\n                </percentage-perception> -->\\r\\n\\r\\n    <lots-form :showDialog.sync=\\\"showDialogLots\\\" :stock=\\\"form.stock\\\" :recordId=\\\"recordId\\\" :lots=\\\"form.lots\\\" @addRowLot=\\\"addRowLot\\\">\\r\\n    </lots-form>\\r\\n    <color-size :showDialog.sync=\\\"showDialogColorSize\\\" :recordId=\\\"recordId\\\" :colorSizes=\\\"form.color_sizes\\\" @addRowColorSize=\\\"addRowColorSize\\\" :stock=\\\"form.stock\\\">\\r\\n    </color-size>\\r\\n</el-dialog>\\r\\n</template>\\r\\n\\r\\n<style>\\r\\n.el-dialog {\\r\\n    border-radius: 10px;\\r\\n    overflow: hidden;\\r\\n}\\r\\n\\r\\n@media screen and (max-width: 1280px) {\\r\\n    .label-text {\\r\\n        display: none;\\r\\n        /* Oculta el texto del label */\\r\\n    }\\r\\n}\\r\\n\\r\\n/* .el-input__inner::-webkit-inner-spin-button,\\r\\n        .el-input__inner::-webkit-outer-spin-button {\\r\\n            -webkit-appearance: none;\\r\\n            margin: 0;\\r\\n        } */\\r\\n</style>\\r\\n\\r\\n<script>\\r\\n// import PercentagePerception from './partials/percentage_perception.vue'\\r\\nimport LotsForm from \\\"./partials/lots.vue\\\";\\r\\nimport ColorSize from \\\"./partials/color_size.vue\\\";\\r\\nexport default {\\r\\n    props: [\\\"showDialog\\\", \\\"recordId\\\", \\\"external\\\", \\\"worker\\\"],\\r\\n    components: {\\r\\n        LotsForm,\\r\\n        ColorSize\\r\\n    },\\r\\n\\r\\n    data() {\\r\\n        return {\\r\\n            loading: true,\\r\\n            allEstablishment: false,\\r\\n            showDialogLots: false,\\r\\n            showDialogColorSize: false,\\r\\n            form_category: {\\r\\n                add: false,\\r\\n                name: null,\\r\\n                id: null\\r\\n            },\\r\\n            form_brand: {\\r\\n                add: false,\\r\\n                name: null,\\r\\n                id: null\\r\\n            },\\r\\n            warehouses: [],\\r\\n            loading_submit: false,\\r\\n            showPercentagePerception: false,\\r\\n            has_percentage_perception: false,\\r\\n            percentage_perception: null,\\r\\n            enabled_percentage_of_profit: false,\\r\\n            titleDialog: null,\\r\\n            resource: \\\"items\\\",\\r\\n            errors: {},\\r\\n            headers: headers_token,\\r\\n            form: {\\r\\n                promotion_count: null\\r\\n            },\\r\\n            configuration: {},\\r\\n            unit_types: [],\\r\\n            areas: [],\\r\\n            currency_types: [],\\r\\n            system_isc_types: [],\\r\\n            affectation_igv_types: [],\\r\\n            categories: [],\\r\\n            brands: [],\\r\\n            accounts: [],\\r\\n            show_has_igv: true,\\r\\n            have_account: false,\\r\\n            showSeries: false,\\r\\n            item_unit_type: {\\r\\n                id: null,\\r\\n                unit_type_id: null,\\r\\n                quantity_unit: 0,\\r\\n                price1: 0,\\r\\n                price2: 0,\\r\\n                price3: 0,\\r\\n                price_default: 2\\r\\n            },\\r\\n            attribute_types: [],\\r\\n            area_id: 2,\\r\\n            timer: null\\r\\n        };\\r\\n    },\\r\\n    async created() {\\r\\n        await this.initForm();\\r\\n        await this.$http.get(`/${this.resource}/tables`).then(response => {\\r\\n            this.unit_types = response.data.unit_types;\\r\\n            this.accounts = response.data.accounts;\\r\\n            this.currency_types = response.data.currency_types;\\r\\n            this.system_isc_types = response.data.system_isc_types;\\r\\n            this.affectation_igv_types = response.data.affectation_igv_types;\\r\\n            this.warehouses = response.data.warehouses;\\r\\n            if (this.warehouses.length > 0) {\\r\\n                this.form.warehouse_id = this.warehouses[0].id;\\r\\n                this.form.warehouse_prices = this.warehouses.map(w => ({\\r\\n                    id: null,\\r\\n                    item_id: null,\\r\\n                    warehouse_id: w.id,\\r\\n                    price: null,\\r\\n                    warehouse: w.description\\r\\n                }));\\r\\n            }\\r\\n            if (this.worker) {\\r\\n                this.warehouses = this.warehouses.filter(\\r\\n                    w => w.establishment_id == this.worker.establishment_id\\r\\n                );\\r\\n                this.form.warehouse_id = this.warehouses[0].id;\\r\\n            }\\r\\n            this.categories = response.data.categories;\\r\\n            this.brands = response.data.brands;\\r\\n            this.attribute_types = response.data.attribute_types;\\r\\n            this.configuration = response.data.configuration;\\r\\n            console.log(\\r\\n                \\\"🚀 ~ awaitthis.$http.get ~ this.configuration:\\\",\\r\\n                this.configuration\\r\\n            );\\r\\n            this.areas = response.data.areas;\\r\\n\\r\\n            this.form.sale_affectation_igv_type_id =\\r\\n                this.affectation_igv_types.length > 0 ?\\r\\n                this.affectation_igv_types[0].id :\\r\\n                null;\\r\\n            this.form.purchase_affectation_igv_type_id =\\r\\n                this.affectation_igv_types.length > 0 ?\\r\\n                this.affectation_igv_types[0].id :\\r\\n                null;\\r\\n\\r\\n            if (!this.configuration.restaurant) {\\r\\n                this.areas = this.areas.filter(\\r\\n                    a =>\\r\\n                    ![\\\"BARRA\\\", \\\"COCINA\\\", \\\"MOZO\\\", \\\"MESA\\\"].some(\\r\\n                        p => p == a.description\\r\\n                    )\\r\\n                );\\r\\n            }\\r\\n            //agregar opciones para entorno restaurante\\r\\n        });\\r\\n\\r\\n        this.$eventHub.$on(\\\"submitPercentagePerception\\\", data => {\\r\\n            this.form.percentage_perception = data;\\r\\n            if (!this.form.percentage_perception)\\r\\n                this.has_percentage_perception = false;\\r\\n        });\\r\\n\\r\\n        this.$eventHub.$on(\\\"reloadTables\\\", () => {\\r\\n            this.reloadTables();\\r\\n        });\\r\\n\\r\\n        await this.setDefaultConfiguration();\\r\\n    },\\r\\n\\r\\n    methods: {\\r\\n        updateCommercialTreatmentItem(idx) {\\r\\n            if (this.timer) clearTimeout(this.timer);\\r\\n            this.timer = setTimeout(async () => {\\r\\n                let commercial_treatment_item = this.form.commercial_treatments[\\r\\n                    idx\\r\\n                ];\\r\\n                const response = await this.$http.post(\\r\\n                    `/commercial_treatment/items/update/${commercial_treatment_item.id}`,\\r\\n                    commercial_treatment_item\\r\\n                );\\r\\n                if (response.data.success) {\\r\\n                    this.$toast.success(\\\"Se actualizó correctamente\\\");\\r\\n                }\\r\\n            }, 700);\\r\\n        },\\r\\n        addRowColorSize(color_sizes) {\\r\\n            this.form.color_sizes = color_sizes;\\r\\n            if(this.form.stock == 0){\\r\\n                this.form.stock = color_sizes.reduce((acc, color_size) => acc + Number(color_size.stock), 0)\\r\\n            }\\r\\n\\r\\n        },\\r\\n        clickColorSize() {\\r\\n            this.showDialogColorSize = true;\\r\\n        },\\r\\n        selectedMax(idx) {\\r\\n            let selected = this.form.item_unit_types[idx].selected;\\r\\n            for (let i = 0; i < this.form.item_unit_types.length; i++) {\\r\\n                let it = this.form.item_unit_types[i];\\r\\n                it.selected = false;\\r\\n            }\\r\\n\\r\\n            this.form.item_unit_types[idx].selected = selected;\\r\\n            if (selected) {\\r\\n                let qty = Number(this.form.item_unit_types[idx].quantity_unit);\\r\\n                !isNaN(qty) && (this.form.max_quantity = qty);\\r\\n            } else {\\r\\n                this.form.max_quantity = null;\\r\\n            }\\r\\n            this.$forceUpdate();\\r\\n        },\\r\\n        undToTotal(idx, amount, qty) {\\r\\n            let arr = this.form.item_unit_types;\\r\\n            if (qty > 0) {\\r\\n                arr[idx].total = Number(amount) * Number(qty);\\r\\n            } else {\\r\\n                this.$toast.warning(\\\"Ingrese una cantidad válida\\\");\\r\\n                arr[idx].price2 = 0;\\r\\n            }\\r\\n        },\\r\\n        totalToUnd(idx, amount, qty) {\\r\\n            let arr = this.form.item_unit_types;\\r\\n            if (qty > 0) {\\r\\n                arr[idx].price2 = Number(amount) / Number(qty);\\r\\n            } else {\\r\\n                this.$toast.warning(\\\"Ingrese una cantidad válida\\\");\\r\\n                arr[idx].total = 0;\\r\\n            }\\r\\n        },\\r\\n        setDefaultConfiguration() {\\r\\n            this.form.sale_affectation_igv_type_id = this.configuration ?\\r\\n                this.configuration.affectation_igv_type_id :\\r\\n                \\\"10\\\";\\r\\n\\r\\n            this.$http.get(`/configurations/record`).then(response => {\\r\\n                this.form.has_igv = response.data.data.include_igv;\\r\\n            });\\r\\n            this.changeAffectationIgvType();\\r\\n        },\\r\\n        clickAddAttribute() {\\r\\n            this.form.attributes.push({\\r\\n                attribute_type_id: null,\\r\\n                description: null,\\r\\n                value: null,\\r\\n                start_date: null,\\r\\n                end_date: null,\\r\\n                duration: null\\r\\n            });\\r\\n        },\\r\\n        async reloadTables() {\\r\\n            await this.$http.get(`/${this.resource}/tables`).then(response => {\\r\\n                this.unit_types = response.data.unit_types;\\r\\n                this.accounts = response.data.accounts;\\r\\n                this.currency_types = response.data.currency_types;\\r\\n                this.system_isc_types = response.data.system_isc_types;\\r\\n                this.affectation_igv_types =\\r\\n                    response.data.affectation_igv_types;\\r\\n                this.warehouses = response.data.warehouses;\\r\\n                this.categories = response.data.categories;\\r\\n                this.brands = response.data.brands;\\r\\n\\r\\n                this.form.sale_affectation_igv_type_id =\\r\\n                    this.affectation_igv_types.length > 0 ?\\r\\n                    this.affectation_igv_types[0].id :\\r\\n                    null;\\r\\n                this.form.purchase_affectation_igv_type_id =\\r\\n                    this.affectation_igv_types.length > 0 ?\\r\\n                    this.affectation_igv_types[0].id :\\r\\n                    null;\\r\\n            });\\r\\n        },\\r\\n        changeLotsEnabled() {\\r\\n            // if(!this.form.lots_enabled){\\r\\n            //     this.form.lot_code = null\\r\\n            //     this.form.lots = []\\r\\n            // }\\r\\n        },\\r\\n        addRowLot(lots) {\\r\\n            this.form.lots = lots;\\r\\n        },\\r\\n        clickLotcode() {\\r\\n            // if(this.form.stock <= 0)\\r\\n            //     return this.$toast.error('El stock debe ser mayor a 0')\\r\\n\\r\\n            this.showDialogLots = true;\\r\\n        },\\r\\n        changeHaveAccount() {\\r\\n            if (!this.have_account) this.form.account_id = null;\\r\\n        },\\r\\n        changeEnabledPercentageOfProfit() {\\r\\n            // if(!this.enabled_percentage_of_profit) this.form.percentage_of_profit = 0\\r\\n        },\\r\\n        clickDelete(id) {\\r\\n            this.$http\\r\\n                .delete(`/${this.resource}/item-unit-type/${id}`)\\r\\n                .then(res => {\\r\\n                    if (res.data.success) {\\r\\n                        this.loadRecord();\\r\\n                        this.$toast.success(\\r\\n     